previewCss:
.darma-loader-darma-custom-089 {
  width: 40px;
  height: 20px;
  background: var(--loader-color, #ffa500);
  position: relative;
  animation: darma-loader-darma-custom-089-l9-0 1.5s infinite linear;
}
.darma-loader-darma-custom-089:before,
.darma-loader-darma-custom-089:after {
   content:"";
   position: absolute;
   background: inherit; 
   bottom: 100%;
   width: 50%;
   height: 100%;
   animation: inherit;
   animation-name: darma-loader-darma-custom-089-l9-1;
}
.darma-loader-darma-custom-089:before {
  left: 0;
  transform-origin: bottom left;
  --s:-1;
}
.darma-loader-darma-custom-089:after {
  right: 0;
  transform-origin: bottom right;
}
@keyframes darma-loader-darma-custom-089-l9-0 {
   0%,10%   {transform:translateY(0%)    scaleY(1)}
   49.99%   {transform:translateY(-50%)  scaleY(1)}
   50%      {transform:translateY(-50%)  scaleY(-1)}
   90%,100% {transform:translateY(-100%) scaleY(-1)}
}
@keyframes darma-loader-darma-custom-089-l9-1 {
   10%,90% {transform: rotate(0deg)}
   50%     {transform: rotate(calc(var(--s,1)*180deg))}
}

